import api from './api';

export const getChansons = () => api.get('/chansons');
export const getChanson = (id) => api.get(`/chansons/${id}`);
export const createChanson = (data) => api.post('/chansons', data);
export const createChansonWithMusic = (formData) => api.post('/chansons/create', formData, { headers: { 'Content-Type': 'multipart/form-data' } });
export const updateChanson = (id, data) => api.put(`/chansons/${id}`, data);
export const updateChansonWithMusic = (id, formData) => api.put(`/chansons/${id}`, formData, { headers: { 'Content-Type': 'multipart/form-data' } });
export const deleteChanson = (id) => api.delete(`/chansons/${id}`);
